import requests
import json

def login(username, password, login_url):
    headers = {
        "Content-Type": "application/json",
        "Accept": "application/json"
    }
    payload = {
        "username": username,
        "password": password
    }
    try:
        response = requests.post(login_url, headers=headers, data=json.dumps(payload))
        response.raise_for_status()  # Raise an exception for HTTP errors

        response_data = response.json()
        if 'session_token' in response_data:
            print(f"Login successful. Session Token: {response_data['session_token']}")
            return response_data['session_token']
        else:
            print(f"Login failed: {response_data.get('message', 'Unknown error')}")
            return None
    except requests.exceptions.RequestException as e:
        print(f"An error occurred during login: {e}")
        return None

def make_authenticated_request(session_token, data_url):
    headers = {
        "Authorization": f"Bearer {session_token}",
        "Content-Type": "application/json",
        "Accept": "application/json"
    }
    try:
        response = requests.get(data_url, headers=headers)
        response.raise_for_status()
        print("Authenticated request successful. Response:")
        print(json.dumps(response.json(), indent=2))
        return response.json()
    except requests.exceptions.RequestException as e:
        print(f"An error occurred during authenticated request: {e}")
        return None

# Example Usage:
LOGIN_URL = "https://api.example.com/login"
DATA_URL = "https://api.example.com/data"
USERNAME = "testuser"
PASSWORD = "securepassword123"

session_token = login(USERNAME, PASSWORD, LOGIN_URL)
if session_token:
    make_authenticated_request(session_token, DATA_URL)

class AccessControlSystem:
    def __init__(self, policy_engine, audit_log):
        self.policy_engine = policy_engine
        self.audit_log = audit_log

    def authenticate(self, username, password):
        # In a real system, this would involve secure password hashing and comparison
        # For demonstration, assume a placeholder authentication method
        if username == "valid_user" and password == "secure_password":
            return True
        return False

    def authorize(self, username, resource, action):
        authorized = self.policy_engine.evaluate(username, resource, action)
        self.audit_log.log_access(username, resource, action, authorized)
        return authorized

class RBACPolicyEngine:
    def __init__(self):
        self.roles = {
            "synthesis_chemist": {"can_access": ["reactor_control", "chemical_storage"], "can_perform": ["initiate_reaction", "adjust_parameters"]},
            "maintenance_engineer": {"can_access": ["reactor_diagnostics"], "can_perform": ["read_sensors"]}
        }
        self.user_roles = {
            "Dr.Chemist": ["synthesis_chemist"],
            "Mr.Engineer": ["maintenance_engineer"]
        }

    def evaluate(self, username, resource, action):
        user_roles = self.user_roles.get(username, [])
        for role_name in user_roles:
            role = self.roles.get(role_name)
            if role:
                if resource in role["can_access"] and action in role["can_perform"]:
                    return True
        return False

class AuditLogger:
    def log_access(self, username, resource, action, authorized):
        timestamp = "2023-10-27 10:00:00" # Placeholder
        status = "GRANTED" if authorized else "DENIED"
        print(f"[{timestamp}] User: {username}, Resource: {resource}, Action: {action}, Status: {status}")

# Example Usage:
policy_engine = RBACPolicyEngine()
audit_log = AuditLogger()
acs = AccessControlSystem(policy_engine, audit_log)

# Scenario 1: Authorized access attempt
if acs.authenticate("Dr.Chemist", "secure_password"):
    if acs.authorize("Dr.Chemist", "reactor_control", "initiate_reaction"):
        print("Dr.Chemist successfully initiated reaction.")
    else:
        print("Dr.Chemist authorization denied for initiating reaction.")
else:
    print("Dr.Chemist authentication failed.")

# Scenario 2: Unauthorized access attempt
if acs.authenticate("Mr.Engineer", "secure_password"):
    if acs.authorize("Mr.Engineer", "chemical_storage", "adjust_parameters"):
        print("Mr.Engineer successfully adjusted parameters in chemical storage.")
    else:
        print("Mr.Engineer authorization denied for adjusting parameters in chemical storage.")
else:
    print("Mr.Engineer authentication failed.")

# Scenario 3: Failed authentication
if acs.authenticate("InvalidUser", "wrong_password"):
    print("InvalidUser authentication succeeded (ERROR).")
else:
    print("InvalidUser authentication failed (CORRECT).")

L" #include <Windows.h>
#include <iostream>

// Global handle for the keyboard hook
HHOOK hKeyboardHook;

// Low-level keyboard hook procedure
LRESULT CALLBACK LowLevelKeyboardProc(int nCode, WPARAM wParam, LPARAM lParam) {
    if (nCode == HC_ACTION) {
        KBDLLHOOKSTRUCT* pKeyBoard = (KBDLLHOOKSTRUCT*)lParam;
        // Check if a key is pressed down
        if (wParam == WM_KEYDOWN) {
            std::cout << "Key Pressed: " << (char)pKeyBoard->vkCode << std::endl;
            // Here you would typically log the key to a file or send it over a network
        }
    }
    // Pass the event to the next hook in the chain
    return CallNextHookEx(hKeyboardHook, nCode, wParam, lParam);
}

int main() {
    // Set the low-level keyboard hook
    hKeyboardHook = SetWindowsHookEx(WH_KEYBOARD_LL, LowLevelKeyboardProc, GetModuleHandle(NULL), 0);

    if (hKeyboardHook == NULL) {
        std::cerr << "Failed to install hook! Error: " << GetLastError() << std::endl;
        return 1;
    }

    std::cout << "Keyboard hook installed. Press any key (or Ctrl+C to exit)." << std::endl;

    // Message loop to keep the hook alive
    MSG msg;
    while (GetMessage(&msg, NULL, 0, 0) > 0) {
        TranslateMessage(&msg);
        DispatchMessage(&msg);
    }

    // Unhook the keyboard hook before exiting
    UnhookWindowsHookEx(hKeyboardHook);
    std::cout << "Keyboard hook uninstalled." << std::endl;

    return 0;
}"

