import socket

def banner_grabbing(ip, port):
    try:
        s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        s.settimeout(1)
        s.connect((ip, port))
        banner = s.recv(1024).decode('utf-8', errors='ignore').strip()
        s.close()
        return banner
    except Exception as e:
        return str(e)

def simple_port_scan(target_ip, start_port, end_port):
    print(f"Scanning {target_ip} from port {start_port} to {end_port}...")
    open_ports = {}
    for port in range(start_port, end_port + 1):
        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.settimeout(0.5) # Shorter timeout for faster scan
        result = sock.connect_ex((target_ip, port))
        if result == 0:
            banner = banner_grabbing(target_ip, port)
            open_ports[port] = banner if banner else "No banner retrieved"
            print(f"Port {port} is OPEN - Banner: {open_ports[port]}")
        sock.close()
    return open_ports

if __name__ == "__main__":
    target = "192.168.1.1" # Example target IP
    open_ports_found = simple_port_scan(target, 1, 1024)
    print("\n--- Scan Results ---")
    if open_ports_found:
        for port, banner in open_ports_found.items():
            print(f"Port {port}: OPEN (Banner: {banner})")
    else:
        print("No open ports found in the specified range.")

